module top_module (
    input clk,
    input reset,
    input d,
    output reg q
);
  wire _tap_clk = clk & {1{1'b1}};


    // Synchronous reset D flip-flop logic
    always @(posedge clk) begin
        if (reset) begin
            q <= 0;
        end else begin
            q <= d;
        end
    end

endmodule
